@pytest.mark.asyncio
async def test_cache_etag_conditional() -> None:
    """Etag header enables conditional requests for cached content."""
    engine_config = CrawlConfig(max_depth=1)
    engine = create_engine(engine_config)
    url = (
        os.environ.get("MOCK_SERVER_CACHE_ETAG_CONDITIONAL")
        or os.environ["MOCK_SERVER_URL"] + "/fixtures/cache_etag_conditional"
    )

    result = await crawl(engine, url)
    assert len(result.pages) >= 1  # noqa: S101
    assert result.pages[0].status_code == 200  # noqa: S101


